<?php
namespace App\Services\Customers; use App\Models\Customers\Customer; use App\Models\Customers\CustomerSetting; use App\Models\Customers\CustomerWalletTransaction; use App\Models\User; use App\Services\AuditLogger; use Illuminate\Support\Facades\DB;
class WalletService { public function __construct(private readonly AuditLogger $audit,private readonly CustomerEventService $events){} public function adjust(Customer $customer,User $user,float $amount,string $description):CustomerWalletTransaction{return DB::transaction(function()use($customer,$user,$amount,$description){$settings=CustomerSetting::firstOrCreate(['company_id'=>$customer->company_id]);$balance=(float)$customer->wallet_balance+$amount;if($balance<0&&!$settings->allow_negative_wallet)throw \Illuminate\Validation\ValidationException::withMessages(['amount'=>'Wallet balance cannot become negative.']);$customer->update(['wallet_balance'=>$balance]);$transaction=CustomerWalletTransaction::create(['company_id'=>$customer->company_id,'customer_id'=>$customer->id,'transaction_type'=>$amount>=0?'adjustment_credit':'adjustment_debit','amount'=>$amount,'balance_after'=>$balance,'description'=>$description,'created_by'=>$user->id]);$this->audit->record('customer.wallet.adjusted',$customer,'Customer wallet adjusted');$this->events->dispatch('customer.wallet.adjusted',$user,$customer,['amount'=>$amount]);return $transaction;});} }
